"use client";

import { useLoginMutation } from "@weema/auth/react-query";
import { useRouter, useSearchParams } from "next/navigation";
import { useState } from "react";
import { sileo } from "sileo";

import { Button } from "@/components/ui/button";

export function LoginForm() {
  const router = useRouter();
  const searchParams = useSearchParams();
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");

  const returnTo = searchParams.get("returnTo") ?? "/";

  const loginMutation = useLoginMutation({
    baseUrl: "/api/auth",
    onSuccess: (data) => {
      sileo.success({
        title: "Logged in",
        description: data.message || "Welcome back.",
      });
      router.push(returnTo);
      router.refresh();
    },
    onError: (error) => {
      sileo.error({
        title: "Login failed",
        description: error.message,
      });
    },
  });

  return (
    <form
      className="space-y-4"
      onSubmit={(event) => {
        event.preventDefault();
        loginMutation.mutate({ email, password });
      }}
    >
      <div className="space-y-1.5">
        <label className="text-sm font-medium" htmlFor="email">
          Email
        </label>
        <input
          id="email"
          type="email"
          autoComplete="email"
          value={email}
          onChange={(event) => setEmail(event.target.value)}
          className="h-10 w-full rounded-md border border-border bg-background px-3 text-sm outline-none ring-0 transition focus:border-primary"
          placeholder="admin@weema.com"
          required
        />
      </div>

      <div className="space-y-1.5">
        <label className="text-sm font-medium" htmlFor="password">
          Password
        </label>
        <input
          id="password"
          type="password"
          autoComplete="current-password"
          value={password}
          onChange={(event) => setPassword(event.target.value)}
          className="h-10 w-full rounded-md border border-border bg-background px-3 text-sm outline-none ring-0 transition focus:border-primary"
          placeholder="Enter your password"
          required
        />
      </div>

      <Button
        type="submit"
        className="h-10 w-full"
        disabled={loginMutation.isPending}
      >
        {loginMutation.isPending ? "Signing in..." : "Sign in"}
      </Button>
    </form>
  );
}

